var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"얘들아! 이쪽이야!","JPN":"みんな！　こっちだよ！","ENG":"Guys! It's this way!","TWN":"各位，這邊！"},"stage":{"bg":"TEHERANRO_NIGHT","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"크게 다친 데는 없는 것 같네. 무사해서 다행이야!","JPN":"大きいケガはしてないようだね、無事でよかった！","ENG":"You guys don't look too bad. I'm glad you're okay!","TWN":"大家好像都沒受什麼重傷呢，真是太好了！"},"stage":{"bg":"TEHERANRO_NIGHT","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"중화기...... 싫어...... 벙커 버스터...... 싫어......","JPN":"重火器……イヤだ……、バンカーバスター……だいきらい……","ENG":"Heavy firearms... I don't like it... Bunker buster... I hate it...","TWN":"討厭……重型武器……討厭……掩體炸彈……"},"stage":{"bg":"TEHERANRO_NIGHT","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"전차 한 대가 하늘로 쾅...... 전차 두 대가 하늘로 쾅...... 전차 세 대가......","JPN":"戦車1台が空を飛んでドカン……戦車2台が空を飛んでドカン……戦車3台が……","ENG":"One tank goes BOOM... Two tanks go BOOM... Three tanks go...","TWN":"一台戰車飛到天空爆炸……兩台戰車飛到天空爆炸……三台戰車……"},"stage":{"bg":"TEHERANRO_NIGHT","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"TEHERANRO_NIGHT","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이봐, 아가씨. 저 친구들 괜찮은 건가?","JPN":"おい、嬢ちゃん。あの子たち、大丈夫なのか？","ENG":"Hey, miss? Are they okay?","TWN":"喂，小姐，那幾位朋友沒事吧？"},"stage":{"bg":"TEHERANRO_NIGHT","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"아무리 봐도 PTSD 초기 증상으로 보이는데......?","JPN":"どう見てもPTSDの初期症状に見えるが……？","ENG":"That looks like the early signs of PTSD...","TWN":"那個樣子不管怎麼看，都像是創傷後遺症的初期症狀啊？"},"stage":{"bg":"TEHERANRO_NIGHT","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"음...... 그 용병 녀석들이 못살게 굴었던 거겠지. 그거 말고 뭐가 있겠어?","JPN":"……あの傭兵野郎どもに散々苦労させられたんだよ。それしかない。","ENG":"Umm... Those mercenary jerks must have given them a hard time... What else could it be?","TWN":"嗯……應該是被那群傭兵折磨的吧，不然呢？"},"stage":{"bg":"TEHERANRO_NIGHT","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......그런가? 그런데 왜 자꾸 이쪽을 원망스럽게 쳐다보고 있는 건지 모르겠군.","JPN":"……そうか？　でも、なんでこっちを恨めしそうに見つめているんだろうな。","ENG":"I guess so... But why does she keep glaring at me?","TWN":"……是嗎？但為什麼她們一直哀怨地瞪著這邊……"},"stage":{"bg":"TEHERANRO_NIGHT","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그, 글쎄......? 그건 나도 잘......","JPN":"さ、さあ……？　私にもよくわから……","ENG":"Err... I'm not sure...","TWN":"誰、誰知道呢？我也不太清……"},"stage":{"bg":"TEHERANRO_NIGHT","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"미, 미나 씨!","JPN":"ミ、ミナさん！","ENG":"M-Mina!","TWN":"米、米娜小姐！"},"stage":{"bg":"TEHERANRO_NIGHT","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"으, 으익?!","JPN":"う、うえっ！？","ENG":"Huh?!","TWN":"嗚哇！？"},"stage":{"bg":"TEHERANRO_NIGHT","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"여기 계셨군요, 미나 씨! 정말 감사드려요!","JPN":"ここにいらしたのですね！　ミナさん、本当にありがとう！","ENG":"I was looking for you, Mina! Thank you so much!","TWN":"妳在這裡呀，米娜小姐！真的是太謝謝妳了！"},"stage":{"bg":"TEHERANRO_NIGHT","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"으, 응......? 가, 감사?","JPN":"う、うん……？　か、感謝？","ENG":"Uh... Thank you?","TWN":"咦……？謝、謝謝我？"},"stage":{"bg":"TEHERANRO_NIGHT","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"네! 미나 씨가 저를 믿어주신 덕분에 해낼 수 있었어요.","JPN":"はい！　ミナさんが私を信じてくれたおかげで、ここまでできました。","ENG":"Yes! I was able to do it because you trusted me!","TWN":"嗯！多虧米娜小姐相信我，我成功了。"},"stage":{"bg":"TEHERANRO_NIGHT","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"제 소심한 성격은 영원히 고칠 수 없다고 생각했었는데, 덕분에 자신감이 생긴 것 같아요.","JPN":"私の臆病な性格はいつまでも直せないと思ってましたが、おかげさまで自信がついたみたいです。","ENG":"I never thought I'd ever break out of my shy bubble... But I'm bursting with confidence thanks to you!","TWN":"我原本以為我永遠無法改掉自己膽怯的性格。但多虧了米娜小姐，我好像變得有自信了。"},"stage":{"bg":"TEHERANRO_NIGHT","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"앞으로도 훌륭한 인간 벙커 버스터가 되기 위해 힘낼 테니까, 지켜봐 주세요!","JPN":"これからも、立派な人間バンカーバスターになるためにがんばりますので、見守ってくださいね！","ENG":"I'll do my best to become the best Human Bunker Buster in the world! I won't let you down!","TWN":"我以後也會為了成為更優秀的人類掩體炸彈努力的，請米娜小姐拭目以待吧！"},"stage":{"bg":"TEHERANRO_NIGHT","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아...... 그, 그래. 행운을 빌게......","JPN":"あ……そ、そう……幸運を祈るよ……","ENG":"Oh... Sure... Good luck...","TWN":"喔，這、這樣喔，那祝妳好運……"},"stage":{"bg":"TEHERANRO_NIGHT","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"TEHERANRO_NIGHT","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};